// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title AchievementNFTSimple
 * @dev Simplified NFT Achievement system for Texas Hold'em Poker
 * Minimal implementation for TRON compatibility
 */
contract AchievementNFTSimple {

    // ============ Events ============
    event Transfer(address indexed from, address indexed to, uint256 indexed tokenId);
    event Approval(address indexed owner, address indexed approved, uint256 indexed tokenId);
    event ApprovalForAll(address indexed owner, address indexed operator, bool approved);
    event AchievementMinted(address indexed player, uint256 indexed tokenId, uint256 achievementTypeId);

    // ============ State Variables ============

    string public name = "Poker Achievement NFT";
    string public symbol = "PANFT";

    uint256 private _tokenIdCounter;
    address public owner;
    address public signer;
    string public baseURI;

    uint256 public signatureValidity = 7 days;

    // Token ownership
    mapping(uint256 => address) private _owners;
    mapping(address => uint256) private _balances;
    mapping(uint256 => address) private _tokenApprovals;
    mapping(address => mapping(address => bool)) private _operatorApprovals;

    // Achievement type ID => Achievement info
    mapping(uint256 => string) public achievementNames;
    mapping(uint256 => uint256) public achievementMonthlyLimits;
    mapping(uint256 => uint256) public achievementMintPrices;

    // YearMonth (YYYYMM) => AchievementType => Minted count
    mapping(uint256 => mapping(uint256 => uint256)) public monthlyMinted;

    // Claim record hash => used
    mapping(bytes32 => bool) public claimRecord;

    // Token ID => Achievement type
    mapping(uint256 => uint256) public tokenAchievementType;

    // ============ Modifiers ============

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    // ============ Constructor ============

    constructor(address _signer, string memory _baseURI) {
        require(_signer != address(0), "Invalid signer");
        owner = msg.sender;
        signer = _signer;
        baseURI = _baseURI;

        // Initialize achievements
        achievementNames[1] = "Royal Flush";
        achievementMonthlyLimits[1] = 10;
        achievementMintPrices[1] = 5 * 1e6;

        achievementNames[2] = "Straight Flush";
        achievementMonthlyLimits[2] = 20;
        achievementMintPrices[2] = 5 * 1e6;

        achievementNames[3] = "Four of a Kind";
        achievementMonthlyLimits[3] = 50;
        achievementMintPrices[3] = 5 * 1e6;

        achievementNames[4] = "Full House";
        achievementMonthlyLimits[4] = 100;
        achievementMintPrices[4] = 5 * 1e6;

        achievementNames[5] = "Flush";
        achievementMonthlyLimits[5] = 200;
        achievementMintPrices[5] = 5 * 1e6;

        achievementNames[6] = "Straight";
        achievementMonthlyLimits[6] = 300;
        achievementMintPrices[6] = 5 * 1e6;
    }

    // ============ ERC721 Functions ============

    function balanceOf(address account) public view returns (uint256) {
        require(account != address(0), "Zero address");
        return _balances[account];
    }

    function ownerOf(uint256 tokenId) public view returns (address) {
        address tokenOwner = _owners[tokenId];
        require(tokenOwner != address(0), "Invalid token");
        return tokenOwner;
    }

    function safeTransferFrom(address from, address to, uint256 tokenId) public {
        require(_isApprovedOrOwner(msg.sender, tokenId), "Not approved");
        _transfer(from, to, tokenId);
    }

    function transferFrom(address from, address to, uint256 tokenId) public {
        require(_isApprovedOrOwner(msg.sender, tokenId), "Not approved");
        _transfer(from, to, tokenId);
    }

    function approve(address to, uint256 tokenId) public {
        address tokenOwner = ownerOf(tokenId);
        require(to != tokenOwner, "Self-approval");
        require(msg.sender == tokenOwner || _operatorApprovals[tokenOwner][msg.sender], "Not authorized");
        _tokenApprovals[tokenId] = to;
        emit Approval(tokenOwner, to, tokenId);
    }

    function getApproved(uint256 tokenId) public view returns (address) {
        require(_exists(tokenId), "Invalid token");
        return _tokenApprovals[tokenId];
    }

    function setApprovalForAll(address operator, bool approved) public {
        _operatorApprovals[msg.sender][operator] = approved;
        emit ApprovalForAll(msg.sender, operator, approved);
    }

    function isApprovedForAll(address owner_, address operator) public view returns (bool) {
        return _operatorApprovals[owner_][operator];
    }

    function supportsInterface(bytes4 interfaceId) public pure returns (bool) {
        return interfaceId == 0x80ac58cd || interfaceId == 0x5b5e139f; // ERC721, ERC721Metadata
    }

    // ============ NFT Claim Functions ============

    function claimNFT(
        uint256 achievementTypeId,
        uint256 timestamp,
        string calldata gameId,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) public payable returns (uint256) {
        _validateClaim(achievementTypeId, timestamp, gameId, v, r, s);

        // Mint NFT
        _tokenIdCounter++;
        uint256 tokenId = _tokenIdCounter;

        _mint(msg.sender, tokenId);
        tokenAchievementType[tokenId] = achievementTypeId;

        uint256 yearMonth = _getYearMonth();
        monthlyMinted[yearMonth][achievementTypeId]++;

        // Refund excess
        uint256 price = achievementMintPrices[achievementTypeId];
        if (msg.value > price) {
            payable(msg.sender).transfer(msg.value - price);
        }

        emit AchievementMinted(msg.sender, tokenId, achievementTypeId);

        return tokenId;
    }

    function _validateClaim(
        uint256 achievementTypeId,
        uint256 timestamp,
        string calldata gameId,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) internal {
        require(achievementTypeId >= 1 && achievementTypeId <= 6, "Invalid type");
        require(msg.value >= achievementMintPrices[achievementTypeId], "Insufficient payment");
        require(block.timestamp <= timestamp + signatureValidity, "Signature expired");
        require(block.timestamp >= timestamp - signatureValidity, "Signature not valid yet");

        // Check monthly limit
        uint256 yearMonth = _getYearMonth();
        require(
            monthlyMinted[yearMonth][achievementTypeId] < achievementMonthlyLimits[achievementTypeId],
            "Monthly limit reached"
        );

        // Verify signature
        bytes32 hash = keccak256(abi.encodePacked(
            msg.sender,
            achievementTypeId,
            timestamp,
            gameId
        ));

        bytes32 ethSignedHash = keccak256(abi.encodePacked("\x19Ethereum Signed Message:\n32", hash));
        address recoveredSigner = ecrecover(ethSignedHash, v, r, s);

        require(recoveredSigner == signer, "Invalid signature");

        // Check for replay
        bytes32 claimHash = keccak256(abi.encodePacked(msg.sender, gameId, achievementTypeId));
        require(!claimRecord[claimHash], "Already claimed");
        claimRecord[claimHash] = true;
    }

    // ============ View Functions ============

    function getMonthlyRemaining(uint256 achievementTypeId) external view returns (uint256) {
        uint256 yearMonth = _getYearMonth();
        uint256 minted = monthlyMinted[yearMonth][achievementTypeId];
        uint256 limit = achievementMonthlyLimits[achievementTypeId];

        return minted >= limit ? 0 : limit - minted;
    }

    function getAchievementInfo(uint256 achievementTypeId) external view returns (
        string memory name,
        uint256 monthlyLimit,
        uint256 mintPrice
    ) {
        return (
            achievementNames[achievementTypeId],
            achievementMonthlyLimits[achievementTypeId],
            achievementMintPrices[achievementTypeId]
        );
    }

    function tokenURI(uint256 tokenId) external view returns (string memory) {
        require(_exists(tokenId), "Invalid token");
        uint256 achievementType = tokenAchievementType[tokenId];
        return string(abi.encodePacked(baseURI, _uint2str(achievementType), "/", _uint2str(tokenId)));
    }

    // ============ Admin Functions ============

    function setSigner(address _signer) external onlyOwner {
        require(_signer != address(0), "Invalid signer");
        signer = _signer;
    }

    function setBaseURI(string memory _baseURI) external onlyOwner {
        baseURI = _baseURI;
    }

    function updateAchievement(
        uint256 achievementTypeId,
        uint256 monthlyLimit,
        uint256 mintPrice
    ) external onlyOwner {
        require(achievementTypeId >= 1 && achievementTypeId <= 6, "Invalid type");
        achievementMonthlyLimits[achievementTypeId] = monthlyLimit;
        achievementMintPrices[achievementTypeId] = mintPrice;
    }

    function withdraw() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }

    // ============ Internal Functions ============

    function _exists(uint256 tokenId) internal view returns (bool) {
        return _owners[tokenId] != address(0);
    }

    function _isApprovedOrOwner(address spender, uint256 tokenId) internal view returns (bool) {
        address tokenOwner = ownerOf(tokenId);
        return spender == tokenOwner || 
               _tokenApprovals[tokenId] == spender || 
               _operatorApprovals[tokenOwner][spender];
    }

    function _transfer(address from, address to, uint256 tokenId) internal {
        require(ownerOf(tokenId) == from, "Wrong owner");
        require(to != address(0), "Zero address");

        _balances[from] -= 1;
        _balances[to] += 1;
        _owners[tokenId] = to;

        emit Transfer(from, to, tokenId);
    }

    function _mint(address to, uint256 tokenId) internal {
        require(to != address(0), "Zero address");
        require(!_exists(tokenId), "Token exists");

        _balances[to] += 1;
        _owners[tokenId] = to;

        emit Transfer(address(0), to, tokenId);
    }

    function _getYearMonth() internal view returns (uint256) {
        uint256 timestamp = block.timestamp;
        uint256 year = 1970 + (timestamp / 31536000);
        uint256 month = ((timestamp % 31536000) / 2592000) + 1;
        return year * 100 + (month > 12 ? 12 : month);
    }

    function _uint2str(uint256 value) internal pure returns (string memory) {
        if (value == 0) return "0";
        uint256 temp = value;
        uint256 digits;
        while (temp != 0) {
            digits++;
            temp /= 10;
        }
        bytes memory buffer = new bytes(digits);
        while (value != 0) {
            digits -= 1;
            buffer[digits] = bytes1(uint8(48 + uint256(value % 10)));
            value /= 10;
        }
        return string(buffer);
    }

    receive() external payable {}
}

contracts/AMMPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title AMMPool
 * @dev AMM流动性池合约，基于恒定乘积公式(x*y=k)
 * 支持TRX/CHIP交易对的自动做市
 */
contract AMMPool {
    // ============ 状态变量 ============

    // TRC20代币地址（CHIP）
    address public token;

    // 储备量
    uint256 public reserveTRX;     // TRX储备量（wei）
    uint256 public reserveCHIP;    // CHIP储备量（microCHIP）

    // LP代币相关
    string public constant name = "AMM LP Token";
    string public constant symbol = "ALP";
    uint8 public constant decimals = 18;
    uint256 public totalSupply;

    // 用户LP代币余额和授权
    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    // 管理员和暂停状态
    address public owner;
    bool public paused;

    // K值记录（用于防闪电贷攻击）
    uint256 public kLast;

    // 价格累积（用于TWAP）
    uint256 public price0CumulativeLast;  // TRX价格累积
    uint256 public price1CumulativeLast;  // CHIP价格累积
    uint32 public blockTimestampLast;

    // 最小流动性（防止除零）
    uint256 public constant MINIMUM_LIQUIDITY = 10**3;

    // 手续费率（0.3% = 997/1000）
    uint256 public constant FEE_NUMERATOR = 997;
    uint256 public constant FEE_DENOMINATOR = 1000;

    // ============ 事件 ============

    event Mint(address indexed sender, uint256 amount0, uint256 amount1, uint256 liquidity);
    event Burn(address indexed sender, uint256 amount0, uint256 amount1, uint256 liquidity);
    event Swap(
        address indexed sender,
        uint256 amount0In,
        uint256 amount1In,
        uint256 amount0Out,
        uint256 amount1Out,
        address indexed to
    );
    event Sync(uint256 reserve0, uint256 reserve1);
    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event PauseChanged(bool paused);

    // ============ 修饰器 ============

    modifier onlyOwner() {
        require(msg.sender == owner, "AMMPool: not owner");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "AMMPool: paused");
        _;
    }

    // 重入锁
    uint256 private _status;
    modifier nonReentrant() {
        require(_status != 2, "AMMPool: reentrant call");
        _status = 2;
        _;
        _status = 1;
    }

    // ============ 构造函数 ============

    constructor(address _token) {
        owner = msg.sender;
        token = _token;
        paused = false;
        _status = 1;
    }

    // ============ TRC20 LP代币接口 ============

    function _transfer(address from, address to, uint256 value) internal {
        require(to != address(0), "AMMPool: transfer to zero address");
        balanceOf[from] -= value;
        balanceOf[to] += value;
        emit Transfer(from, to, value);
    }

    function transfer(address to, uint256 value) external returns (bool) {
        _transfer(msg.sender, to, value);
        return true;
    }

    function approve(address spender, uint256 value) external returns (bool) {
        allowance[msg.sender][spender] = value;
        emit Approval(msg.sender, spender, value);
        return true;
    }

    function transferFrom(address from, address to, uint256 value) external returns (bool) {
        uint256 allowed = allowance[from][msg.sender];
        if (allowed != type(uint256).max) {
            allowance[from][msg.sender] = allowed - value;
        }
        _transfer(from, to, value);
        return true;
    }

    // ============ 核心AMM功能 ============

    /**
     * @dev 获取当前储备量
     * @return _reserveTRX TRX储备量
     * @return _reserveCHIP CHIP储备量
     * @return _blockTimestampLast 最后更新区块时间
     */
    function getReserves() external view returns (
        uint256 _reserveTRX,
        uint256 _reserveCHIP,
        uint32 _blockTimestampLast
    ) {
        _reserveTRX = reserveTRX;
        _reserveCHIP = reserveCHIP;
        _blockTimestampLast = blockTimestampLast;
    }

    /**
     * @dev 更新储备量和价格累积
     */
    function _update(uint256 balance0, uint256 balance1) internal {
        uint32 blockTimestamp = uint32(block.timestamp % 2**32);
        uint32 timeElapsed = blockTimestamp - blockTimestampLast;

        if (timeElapsed > 0 && reserveTRX > 0 && reserveCHIP > 0) {
            // 累积价格（用于TWAP）
            price0CumulativeLast += uint256((reserveCHIP * 1e18) / reserveTRX) * timeElapsed;
            price1CumulativeLast += uint256((reserveTRX * 1e18) / reserveCHIP) * timeElapsed;
        }

        reserveTRX = balance0;
        reserveCHIP = balance1;
        blockTimestampLast = blockTimestamp;
        emit Sync(balance0, balance1);
    }

    /**
     * @dev 铸造LP代币
     * @param to 接收LP代币的地址
     * @return liquidity 铸造的LP代币数量
     */
    function mint(address to) external nonReentrant whenNotPaused returns (uint256 liquidity) {
        uint256 _totalSupply = totalSupply;
        uint256 _reserveTRX = reserveTRX;
        uint256 _reserveCHIP = reserveCHIP;

        uint256 balance0 = address(this).balance;
        uint256 balance1 = ITRC20(token).balanceOf(address(this));

        uint256 amount0 = balance0 - _reserveTRX;
        uint256 amount1 = balance1 - _reserveCHIP;

        if (_totalSupply == 0) {
            // 首次添加流动性
            liquidity = sqrt(amount0 * amount1) - MINIMUM_LIQUIDITY;
            // 永久锁定最小流动性，防止池子被清空
            balanceOf[address(0)] = MINIMUM_LIQUIDITY;
            totalSupply = MINIMUM_LIQUIDITY;
        } else {
            // 后续添加流动性，按较小比例铸造
            liquidity = min(
                (amount0 * _totalSupply) / _reserveTRX,
                (amount1 * _totalSupply) / _reserveCHIP
            );
        }

        require(liquidity > 0, "AMMPool: insufficient liquidity minted");

        totalSupply += liquidity;
        balanceOf[to] += liquidity;

        _update(balance0, balance1);
        kLast = reserveTRX * reserveCHIP;

        emit Mint(msg.sender, amount0, amount1, liquidity);
        emit Transfer(address(0), to, liquidity);
    }

    /**
     * @dev 燃烧LP代币，取回流动性
     * @param to 接收代币的地址
     * @return amount0 取回的TRX数量
     * @return amount1 取回的CHIP数量
     */
    function burn(address to) external nonReentrant whenNotPaused returns (
        uint256 amount0,
        uint256 amount1
    ) {
        uint256 liquidity = balanceOf[msg.sender];
        require(liquidity > 0, "AMMPool: insufficient liquidity");

        uint256 _totalSupply = totalSupply;
        uint256 _reserveTRX = reserveTRX;
        uint256 _reserveCHIP = reserveCHIP;

        // 按比例计算可取回的数量
        amount0 = (liquidity * _reserveTRX) / _totalSupply;
        amount1 = (liquidity * _reserveCHIP) / _totalSupply;

        require(amount0 > 0 && amount1 > 0, "AMMPool: insufficient liquidity burned");

        totalSupply = _totalSupply - liquidity;
        balanceOf[msg.sender] = balanceOf[msg.sender] - liquidity;

        // 转账TRX
        (bool success, ) = payable(to).call{value: amount0}("");
        require(success, "AMMPool: TRX transfer failed");

        // 转账CHIP
        ITRC20(token).transfer(to, amount1);

        uint256 balance0 = address(this).balance;
        uint256 balance1 = ITRC20(token).balanceOf(address(this));

        _update(balance0, balance1);
        kLast = reserveTRX * reserveCHIP;

        emit Burn(msg.sender, amount0, amount1, liquidity);
        emit Transfer(msg.sender, address(0), liquidity);
    }

    /**
     * @dev 执行交换
     * @param amount0Out 输出TRX数量（卖CHIP时设置）
     * @param amount1Out 输出CHIP数量（买CHIP时设置）
     * @param to 接收输出代币的地址
     * @param data 回调数据（可选）
     */
    function swap(
        uint256 amount0Out,
        uint256 amount1Out,
        address to,
        bytes calldata data
    ) external nonReentrant whenNotPaused {
        require(amount0Out > 0 || amount1Out > 0, "AMMPool: insufficient output amount");
        require(amount0Out < reserveTRX && amount1Out < reserveCHIP, "AMMPool: insufficient liquidity");

        uint256 balance0;
        uint256 balance1;

        // 转账输出代币
        if (amount0Out > 0) {
            (bool success, ) = payable(to).call{value: amount0Out}("");
            require(success, "AMMPool: TRX transfer failed");
        }
        if (amount1Out > 0) {
            ITRC20(token).transfer(to, amount1Out);
        }

        // 回调（用于闪电贷，可选）
        if (data.length > 0) {
            IAMMCallee(to).ammCall(msg.sender, amount0Out, amount1Out, data);
        }

        balance0 = address(this).balance;
        balance1 = ITRC20(token).balanceOf(address(this));

        uint256 amount0In = balance0 > reserveTRX - amount0Out 
            ? balance0 - (reserveTRX - amount0Out) 
            : 0;
        uint256 amount1In = balance1 > reserveCHIP - amount1Out 
            ? balance1 - (reserveCHIP - amount1Out) 
            : 0;

        require(amount0In > 0 || amount1In > 0, "AMMPool: insufficient input amount");

        // 验证K值（扣除手续费后K值应不减少）
        uint256 balance0Adjusted = balance0 * 1000 - amount0In * 3;
        uint256 balance1Adjusted = balance1 * 1000 - amount1In * 3;
        require(
            balance0Adjusted * balance1Adjusted >= reserveTRX * reserveCHIP * 1000**2,
            "AMMPool: K value check failed"
        );

        _update(balance0, balance1);

        emit Swap(
            msg.sender,
            amount0In,
            amount1In,
            amount0Out,
            amount1Out,
            to
        );
    }

    /**
     * @dev 同步储备量（强制更新）
     */
    function sync() external nonReentrant {
        _update(address(this).balance, ITRC20(token).balanceOf(address(this)));
    }

    // ============ 查询函数 ============

    /**
     * @dev 计算输入TRX可获得多少CHIP
     * @param amountIn 输入TRX数量
     * @return amountOut 输出CHIP数量
     */
    function getAmountOutTRXToCHIP(uint256 amountIn) external view returns (uint256 amountOut) {
        require(amountIn > 0, "AMMPool: insufficient input amount");
        uint256 reserveIn = reserveTRX;
        uint256 reserveOut = reserveCHIP;
        require(reserveIn > 0 && reserveOut > 0, "AMMPool: insufficient liquidity");

        uint256 amountInWithFee = amountIn * FEE_NUMERATOR;
        uint256 numerator = amountInWithFee * reserveOut;
        uint256 denominator = reserveIn * FEE_DENOMINATOR + amountInWithFee;
        amountOut = numerator / denominator;
    }

    /**
     * @dev 计算输入CHIP可获得多少TRX
     * @param amountIn 输入CHIP数量
     * @return amountOut 输出TRX数量
     */
    function getAmountOutCHIPToTRX(uint256 amountIn) external view returns (uint256 amountOut) {
        require(amountIn > 0, "AMMPool: insufficient input amount");
        uint256 reserveIn = reserveCHIP;
        uint256 reserveOut = reserveTRX;
        require(reserveIn > 0 && reserveOut > 0, "AMMPool: insufficient liquidity");

        uint256 amountInWithFee = amountIn * FEE_NUMERATOR;
        uint256 numerator = amountInWithFee * reserveOut;
        uint256 denominator = reserveIn * FEE_DENOMINATOR + amountInWithFee;
        amountOut = numerator / denominator;
    }

    /**
     * @dev 计算当前价格（CHIP/TRX）
     * @return price 1 TRX = ? CHIP
     */
    function getCurrentPrice() external view returns (uint256 price) {
        require(reserveTRX > 0, "AMMPool: no liquidity");
        price = (reserveCHIP * 1e18) / reserveTRX;
    }

    // ============ 管理功能 ============

    /**
     * @dev 设置暂停状态
     */
    function setPause(bool _paused) external onlyOwner {
        paused = _paused;
        emit PauseChanged(_paused);
    }

    /**
     * @dev 转移管理员权限
     */
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "AMMPool: zero address");
        owner = newOwner;
    }

    // ============ 辅助函数 ============

    function sqrt(uint256 y) internal pure returns (uint256 z) {
        if (y > 3) {
            z = y;
            uint256 x = y / 2 + 1;
            while (x < z) {
                z = x;
                x = (y / x + x) / 2;
            }
        } else if (y != 0) {
            z = 1;
        }
    }

    function min(uint256 a, uint256 b) internal pure returns (uint256) {
        return a < b ? a : b;
    }

    // ============ 接收TRX ============

    receive() external payable {}
}

// ============ 接口定义 ============

interface ITRC20 {
    function transfer(address to, uint256 value) external returns (bool);
    function transferFrom(address from, address to, uint256 value) external returns (bool);
    function approve(address spender, uint256 value) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function allowance(address owner, address spender) external view returns (uint256);
}

interface IAMMCallee {
    function ammCall(
        address sender,
        uint256 amount0,
        uint256 amount1,
        bytes calldata data
    ) external;
}

contracts/AMMRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "./AMMPool.sol";

/**
 * @title AMMRouter
 * @dev AMM路由合约，作为用户交互入口
 * 提供便捷的添加流动性、移除流动性、交换等接口
 */
contract AMMRouter {
    // ============ 状态变量 ============

    address public factory;
    address public pool;
    address public token;  // CHIP token address

    // 管理员
    address public owner;

    // ============ 事件 ============

    event LiquidityAdded(
        address indexed sender,
        uint256 amountTRX,
        uint256 amountCHIP,
        uint256 liquidity
    );

    event LiquidityRemoved(
        address indexed sender,
        uint256 amountTRX,
        uint256 amountCHIP,
        uint256 liquidity
    );

    event SwapExecuted(
        address indexed sender,
        bool trxToChip,
        uint256 amountIn,
        uint256 amountOut
    );

    // ============ 修饰器 ============

    modifier onlyOwner() {
        require(msg.sender == owner, "AMMRouter: not owner");
        _;
    }

    modifier ensure(uint256 deadline) {
        require(block.timestamp <= deadline, "AMMRouter: expired deadline");
        _;
    }

    // ============ 构造函数 ============

    constructor(address _pool, address _token) {
        owner = msg.sender;
        pool = _pool;
        token = _token;
    }

    // ============ 添加流动性 ============

    /**
     * @dev 添加TRX/CHIP流动性
     * @param amountCHIPDesired 期望存入的CHIP数量
     * @param amountCHIPMin 最小CHIP数量（滑点保护）
     * @param amountTRXMin 最小TRX数量（滑点保护）
     * @param to 接收LP代币的地址
     * @param deadline 交易截止时间
     * @return amountTRX 实际存入的TRX数量
     * @return amountCHIP 实际存入的CHIP数量
     * @return liquidity 铸造的LP代币数量
     */
    function addLiquidity(
        uint256 amountCHIPDesired,
        uint256 amountCHIPMin,
        uint256 amountTRXMin,
        address to,
        uint256 deadline
    ) external payable ensure(deadline) returns (
        uint256 amountTRX,
        uint256 amountCHIP,
        uint256 liquidity
    ) {
        require(msg.value > 0, "AMMRouter: insufficient TRX amount");
        require(amountCHIPDesired > 0, "AMMRouter: insufficient CHIP amount");

        (uint256 reserveTRX, uint256 reserveCHIP, ) = IAMMPool(pool).getReserves();

        if (reserveTRX == 0 && reserveCHIP == 0) {
            // 首次添加流动性，使用用户提供的比例
            amountTRX = msg.value;
            amountCHIP = amountCHIPDesired;
        } else {
            // 计算最优存入比例
            uint256 optimalCHIPAmount = (msg.value * reserveCHIP) / reserveTRX;

            if (optimalCHIPAmount <= amountCHIPDesired) {
                // TRX是限制因素
                require(optimalCHIPAmount >= amountCHIPMin, "AMMRouter: insufficient CHIP amount");
                amountTRX = msg.value;
                amountCHIP = optimalCHIPAmount;
            } else {
                // CHIP是限制因素
                uint256 optimalTRXAmount = (amountCHIPDesired * reserveTRX) / reserveCHIP;
                require(optimalTRXAmount <= msg.value, "AMMRouter: excessive TRX amount");
                require(optimalTRXAmount >= amountTRXMin, "AMMRouter: insufficient TRX amount");
                amountTRX = optimalTRXAmount;
                amountCHIP = amountCHIPDesired;
            }
        }

        // 转账CHIP到池子
        ITRC20(token).transferFrom(msg.sender, address(this), amountCHIP);
        ITRC20(token).approve(pool, amountCHIP);

        // 转账TRX和CHIP到池子（多余的TRX返还）
        (bool success, ) = payable(pool).call{value: amountTRX}("");
        require(success, "AMMRouter: TRX transfer failed");
        ITRC20(token).transfer(pool, amountCHIP);

        // 铸造LP代币
        liquidity = IAMMPool(pool).mint(to);

        // 返还多余的TRX
        if (msg.value > amountTRX) {
            (success, ) = payable(msg.sender).call{value: msg.value - amountTRX}("");
            require(success, "AMMRouter: TRX refund failed");
        }

        emit LiquidityAdded(msg.sender, amountTRX, amountCHIP, liquidity);
    }

    // ============ 移除流动性 ============

    /**
     * @dev 移除TRX/CHIP流动性
     * @param liquidity 要燃烧的LP代币数量
     * @param amountTRXMin 最小取回TRX数量（滑点保护）
     * @param amountCHIPMin 最小取回CHIP数量（滑点保护）
     * @param to 接收代币的地址
     * @param deadline 交易截止时间
     * @return amountTRX 取回的TRX数量
     * @return amountCHIP 取回的CHIP数量
     */
    function removeLiquidity(
        uint256 liquidity,
        uint256 amountTRXMin,
        uint256 amountCHIPMin,
        address to,
        uint256 deadline
    ) external ensure(deadline) returns (
        uint256 amountTRX,
        uint256 amountCHIP
    ) {
        require(liquidity > 0, "AMMRouter: insufficient liquidity");

        // 转入LP代币
        IAMMPool(pool).transferFrom(msg.sender, pool, liquidity);

        // 燃烧LP代币，取回TRX和CHIP
        (amountTRX, amountCHIP) = IAMMPool(pool).burn(to);

        require(amountTRX >= amountTRXMin, "AMMRouter: insufficient TRX amount");
        require(amountCHIP >= amountCHIPMin, "AMMRouter: insufficient CHIP amount");

        emit LiquidityRemoved(msg.sender, amountTRX, amountCHIP, liquidity);
    }

    // ============ 交换功能 ============

    /**
     * @dev 使用TRX购买CHIP
     * @param amountOutMin 最小输出CHIP数量（滑点保护）
     * @param to 接收CHIP的地址
     * @param deadline 交易截止时间
     * @return amountOut 实际获得的CHIP数量
     */
    function swapTRXForCHIP(
        uint256 amountOutMin,
        address to,
        uint256 deadline
    ) external payable ensure(deadline) returns (uint256 amountOut) {
        require(msg.value > 0, "AMMRouter: insufficient TRX amount");

        // 计算输出数量
        amountOut = IAMMPool(pool).getAmountOutTRXToCHIP(msg.value);
        require(amountOut >= amountOutMin, "AMMRouter: insufficient output amount");

        // 转账TRX到池子并执行交换
        (bool success, ) = payable(pool).call{value: msg.value}("");
        require(success, "AMMRouter: TRX transfer failed");
        IAMMPool(pool).swap(0, amountOut, to, "");

        emit SwapExecuted(msg.sender, true, msg.value, amountOut);
    }

    /**
     * @dev 使用CHIP购买TRX
     * @param amountIn 输入CHIP数量
     * @param amountOutMin 最小输出TRX数量（滑点保护）
     * @param to 接收TRX的地址
     * @param deadline 交易截止时间
     * @return amountOut 实际获得的TRX数量
     */
    function swapCHIPForTRX(
        uint256 amountIn,
        uint256 amountOutMin,
        address to,
        uint256 deadline
    ) external ensure(deadline) returns (uint256 amountOut) {
        require(amountIn > 0, "AMMRouter: insufficient CHIP amount");

        // 计算输出数量
        amountOut = IAMMPool(pool).getAmountOutCHIPToTRX(amountIn);
        require(amountOut >= amountOutMin, "AMMRouter: insufficient output amount");

        // 转账CHIP到池子
        ITRC20(token).transferFrom(msg.sender, pool, amountIn);

        // 执行交换
        IAMMPool(pool).swap(amountOut, 0, to, "");

        emit SwapExecuted(msg.sender, false, amountIn, amountOut);
    }

    // ============ 查询函数 ============

    /**
     * @dev 预估TRX转CHIP的输出
     * @param amountIn 输入TRX数量
     * @return amountOut 预估输出CHIP数量
     */
    function quoteTRXToCHIP(uint256 amountIn) external view returns (uint256 amountOut) {
        amountOut = IAMMPool(pool).getAmountOutTRXToCHIP(amountIn);
    }

    /**
     * @dev 预估CHIP转TRX的输出
     * @param amountIn 输入CHIP数量
     * @return amountOut 预估输出TRX数量
     */
    function quoteCHIPToTRX(uint256 amountIn) external view returns (uint256 amountOut) {
        amountOut = IAMMPool(pool).getAmountOutCHIPToTRX(amountIn);
    }

    /**
     * @dev 获取当前储备量和价格
     * @return reserveTRX TRX储备量
     * @return reserveCHIP CHIP储备量
     * @return price 当前价格（1 TRX = ? CHIP）
     */
    function getPoolInfo() external view returns (
        uint256 reserveTRX,
        uint256 reserveCHIP,
        uint256 price
    ) {
        (reserveTRX, reserveCHIP, ) = IAMMPool(pool).getReserves();
        if (reserveTRX > 0) {
            price = IAMMPool(pool).getCurrentPrice();
        }
    }

    /**
     * @dev 计算价格影响
     * @param amountIn 输入数量
     * @param isTRXToCHIP 是否是TRX转CHIP
     * @return priceImpact 价格影响百分比（乘以10000）
     */
    function getPriceImpact(
        uint256 amountIn,
        bool isTRXToCHIP
    ) external view returns (uint256 priceImpact) {
        (uint256 reserveTRX, uint256 reserveCHIP, ) = IAMMPool(pool).getReserves();

        if (isTRXToCHIP) {
            require(reserveTRX > 0, "AMMRouter: no liquidity");
            priceImpact = (amountIn * 10000) / (reserveTRX + amountIn);
        } else {
            require(reserveCHIP > 0, "AMMRouter: no liquidity");
            priceImpact = (amountIn * 10000) / (reserveCHIP + amountIn);
        }
    }

    // ============ 管理功能 ============

    /**
     * @dev 更新池子地址
     */
    function setPool(address _pool) external onlyOwner {
        require(_pool != address(0), "AMMRouter: zero address");
        pool = _pool;
    }

    /**
     * @dev 更新代币地址
     */
    function setToken(address _token) external onlyOwner {
        require(_token != address(0), "AMMRouter: zero address");
        token = _token;
    }

    /**
     * @dev 转移管理员权限
     */
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "AMMRouter: zero address");
        owner = newOwner;
    }

    // ============ 接收TRX ============

    receive() external payable {}
}

// ============ 接口定义 ============

interface IAMMPool {
    function getReserves() external view returns (uint256 reserveTRX, uint256 reserveCHIP, uint256 blockTimestampLast);
    function mint(address to) external returns (uint256 liquidity);
    function burn(address to) external returns (uint256 amountTRX, uint256 amountCHIP);
    function swap(uint256 amountTRXOut, uint256 amountCHIPOut, address to, bytes calldata data) external;
    function getAmountOutTRXToCHIP(uint256 amountIn) external view returns (uint256 amountOut);
    function getAmountOutCHIPToTRX(uint256 amountIn) external view returns (uint256 amountOut);
    function getCurrentPrice() external view returns (uint256 price);
    function transferFrom(address from, address to, uint256 value) external returns (bool);
}

contracts/ChipToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

/**
 * @title ChipToken
 * @dev CHIP platform token for the poker game ecosystem
 * ERC20 standard with minting controls and VIP benefits
 */
contract ChipToken is ERC20, ERC20Burnable, Ownable, Pausable {

    // ============ Constants ============

    uint256 public constant MAX_SUPPLY = 1_000_000 * 1e6; // 1 million with 6 decimals (burned from original 1 billion)
    uint8 private constant DECIMALS = 6;

    // ============ State Variables ============

    // Minter whitelist
    mapping(address => bool) public isMinter;
    address[] public minters;

    // VIP thresholds (adjusted for 1M total supply)
    uint256 public vipThreshold = 1_000 * 1e6; // 1,000 CHIP for Silver VIP
    uint256 public superVipThreshold = 10_000 * 1e6; // 10,000 CHIP for Gold VIP
    uint256 public platinumVipThreshold = 100_000 * 1e6; // 100,000 CHIP for Platinum VIP

    // VIP discount rates (in basis points)
    uint256 public vipDiscount = 500;    // 5% discount for VIP
    uint256 public superVipDiscount = 1000; // 10% discount for Super VIP

    // Total minted
    uint256 public totalMinted;

    // ============ Events ============

    event MinterAdded(address indexed minter);
    event MinterRemoved(address indexed minter);
    event Minted(address indexed to, uint256 amount, address indexed minter);
    event Burned(address indexed from, uint256 amount);
    event VipThresholdUpdated(uint256 newThreshold);
    event VipDiscountUpdated(uint256 vipDiscount, uint256 superVipDiscount);

    // ============ Modifiers ============

    modifier onlyMinter() {
        require(isMinter[msg.sender], "ChipToken: caller is not minter");
        _;
    }

    // ============ Constructor ============

    constructor(uint256 initialSupply) 
        ERC20("CHIP Token", "CHIP") 

    {
        require(initialSupply <= MAX_SUPPLY, "ChipToken: exceeds max supply");

        // Mint initial supply to deployer
        _mint(msg.sender, initialSupply);
        totalMinted = initialSupply;

        // Deployer is a minter by default
        _addMinter(msg.sender);
    }

    // ============ ERC20 Overrides ============

    function decimals() public pure override returns (uint8) {
        return DECIMALS;
    }

    function transfer(address to, uint256 amount) 
        public 
        override 
        whenNotPaused 
        returns (bool) 
    {
        return super.transfer(to, amount);
    }

    function transferFrom(address from, address to, uint256 amount) 
        public 
        override 
        whenNotPaused 
        returns (bool) 
    {
        return super.transferFrom(from, to, amount);
    }

    // ============ Minting Functions ============

    /**
     * @dev Mint new tokens (only minters)
     * @param to Recipient address
     * @param amount Amount to mint
     */
    function mint(address to, uint256 amount) external onlyMinter whenNotPaused {
        require(to != address(0), "ChipToken: mint to zero address");
        require(totalMinted + amount <= MAX_SUPPLY, "ChipToken: exceeds max supply");

        _mint(to, amount);
        totalMinted += amount;

        emit Minted(to, amount, msg.sender);
    }

    /**
     * @dev Burn tokens from caller
     * @param amount Amount to burn
     */
    function burn(uint256 amount) public override whenNotPaused {
        super.burn(amount);
        emit Burned(msg.sender, amount);
    }

    /**
     * @dev Burn tokens from another account (with allowance)
     * @param account Account to burn from
     * @param amount Amount to burn
     */
    function burnFrom(address account, uint256 amount) public override whenNotPaused {
        super.burnFrom(account, amount);
        emit Burned(account, amount);
    }

    // ============ Minter Management ============

    function addMinter(address minter) external onlyOwner {
        _addMinter(minter);
    }

    function removeMinter(address minter) external onlyOwner {
        require(isMinter[minter], "ChipToken: not a minter");
        require(minter != owner(), "ChipToken: cannot remove owner");

        isMinter[minter] = false;

        // Remove from array
        for (uint256 i = 0; i < minters.length; i++) {
            if (minters[i] == minter) {
                minters[i] = minters[minters.length - 1];
                minters.pop();
                break;
            }
        }

        emit MinterRemoved(minter);
    }

    function _addMinter(address minter) internal {
        require(minter != address(0), "ChipToken: invalid minter");
        require(!isMinter[minter], "ChipToken: already minter");

        isMinter[minter] = true;
        minters.push(minter);

        emit MinterAdded(minter);
    }

    function getMinters() external view returns (address[] memory) {
        return minters;
    }

    // ============ VIP Functions ============

    /**
     * @dev Check if address is VIP
     * @param account Address to check
     */
    function isVip(address account) external view returns (bool) {
        return balanceOf(account) >= vipThreshold;
    }

    /**
     * @dev Check if address is Super VIP
     * @param account Address to check
     */
    function isSuperVip(address account) external view returns (bool) {
        return balanceOf(account) >= superVipThreshold;
    }

    /**
     * @dev Get VIP discount for an address
     * @param account Address to check
     * @return Discount in basis points
     */
    function getVipDiscount(address account) external view returns (uint256) {
        uint256 balance = balanceOf(account);

        if (balance >= superVipThreshold) {
            return superVipDiscount;
        } else if (balance >= vipThreshold) {
            return vipDiscount;
        }

        return 0;
    }

    /**
     * @dev Calculate discounted amount for VIP
     * @param account Address to check
     * @param originalAmount Original amount
     * @return Discounted amount
     */
    function applyVipDiscount(address account, uint256 originalAmount) 
        external 
        view 
        returns (uint256) 
    {
        uint256 discount = this.getVipDiscount(account);

        if (discount == 0) {
            return originalAmount;
        }

        return originalAmount * (10000 - discount) / 10000;
    }

    // ============ Admin Functions ============

    function setVipThreshold(uint256 _vipThreshold, uint256 _superVipThreshold) 
        external 
        onlyOwner 
    {
        require(_superVipThreshold > _vipThreshold, "ChipToken: invalid thresholds");
        vipThreshold = _vipThreshold;
        superVipThreshold = _superVipThreshold;
        emit VipThresholdUpdated(_vipThreshold);
    }

    function setVipDiscount(uint256 _vipDiscount, uint256 _superVipDiscount) 
        external 
        onlyOwner 
    {
        require(_vipDiscount <= 2000, "ChipToken: VIP discount too high"); // Max 20%
        require(_superVipDiscount <= 3000, "ChipToken: Super VIP discount too high"); // Max 30%
        vipDiscount = _vipDiscount;
        superVipDiscount = _superVipDiscount;
        emit VipDiscountUpdated(_vipDiscount, _superVipDiscount);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    // ============ Rescue Functions ============

    /**
     * @dev Rescue TRX sent to contract
     */
    function rescueTRX() external onlyOwner {
        uint256 balance = address(this).balance;
        (bool success, ) = payable(owner()).call{value: balance}("");
        require(success, "ChipToken: rescue failed");
    }

    /**
     * @dev Rescue ERC20 tokens sent to contract
     */
    function rescueTokens(address token, uint256 amount) external onlyOwner {
        require(token != address(this), "ChipToken: cannot rescue own token");
        IERC20(token).transfer(owner(), amount);
    }

    // ============ Receive ============

    receive() external payable {}
    fallback() external payable {}
}

contracts/Governance.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";

/**
 * @title Governance
 * @dev DAO Governance Contract for CHIP holders
 * Simple governance with voting, quorum, and proposal execution
 */
contract Governance is Ownable, Pausable {
    using SafeERC20 for IERC20;
    using EnumerableSet for EnumerableSet.UintSet;

    // ============ Enums ============

    enum ProposalState {
        PENDING,
        ACTIVE,
        SUCCEEDED,
        DEFEATED,
        EXECUTED,
        EXPIRED
    }

    enum VoteType {
        AGAINST,
        FOR,
        ABSTAIN
    }

    // ============ Structs ============

    struct Proposal {
        uint256 id;
        address proposer;
        address target;
        bytes callData;
        uint256 startBlock;
        uint256 endBlock;
        uint256 forVotes;
        uint256 againstVotes;
        uint256 abstainVotes;
        uint256 quorumVotes;
        bool executed;
        string description;
        ProposalState state;
    }

    // ============ State Variables ============

    IERC20 public chipToken;

    uint256 public votingPeriod = 3 days;       // Default 3 days
    uint256 public proposalThreshold = 1000 * 1e6; // 1000 CHIP to create proposal
    uint256 public quorumNumerator = 100;       // 10% quorum (100/1000)

    uint256 public proposalCount;

    mapping(uint256 => Proposal) public proposals;
    mapping(uint256 => mapping(address => bool)) public hasVoted;
    mapping(uint256 => mapping(address => uint256)) public votes; // 0=against, 1=for, 2=abstain

    EnumerableSet.UintSet private activeProposals;

    // ============ Events ============

    event ProposalCreated(
        uint256 indexed proposalId,
        address indexed proposer,
        address target,
        string description
    );
    event VoteCast(
        uint256 indexed proposalId,
        address indexed voter,
        uint8 support,
        uint256 weight
    );
    event ProposalExecuted(uint256 indexed proposalId, bool success);
    event ProposalStateChanged(uint256 indexed proposalId, ProposalState newState);
    event VotingPeriodUpdated(uint256 newPeriod);
    event ProposalThresholdUpdated(uint256 newThreshold);

    // ============ Constructor ============

    constructor(
        address _chipToken,
        uint256 _votingPeriod,
        uint256 _proposalThreshold,
        uint256 _quorumNumerator
    )  {
        require(_chipToken != address(0), "Governance: invalid token");

        chipToken = IERC20(_chipToken);
        votingPeriod = _votingPeriod;
        proposalThreshold = _proposalThreshold;
        quorumNumerator = _quorumNumerator;
    }

    // ============ Core Functions ============

    /**
     * @dev Create a new proposal
     * @param target Target contract address
     * @param callData Encoded function call
     * @param description Proposal description
     */
    function createProposal(
        address target,
        bytes calldata callData,
        string calldata description
    ) external whenNotPaused returns (uint256) {
        require(target != address(0), "Governance: invalid target");

        // Check proposal threshold
        uint256 balance = chipToken.balanceOf(msg.sender);
        require(balance >= proposalThreshold, "Governance: below threshold");

        proposalCount++;
        uint256 proposalId = proposalCount;

        Proposal storage newProposal = proposals[proposalId];
        newProposal.id = proposalId;
        newProposal.proposer = msg.sender;
        newProposal.target = target;
        newProposal.callData = callData;
        newProposal.description = description;
        newProposal.startBlock = block.number;
        newProposal.endBlock = block.number + (votingPeriod / 3 seconds); // Approx blocks
        newProposal.state = ProposalState.ACTIVE;
        newProposal.quorumVotes = chipToken.totalSupply() * quorumNumerator / 1000;

        activeProposals.add(proposalId);

        emit ProposalCreated(proposalId, msg.sender, target, description);

        return proposalId;
    }

    /**
     * @dev Cast vote on a proposal
     * @param proposalId Proposal ID
     * @param support 0=Against, 1=For, 2=Abstain
     */
    function castVote(uint256 proposalId, uint8 support) 
        external 
        whenNotPaused 
    {
        Proposal storage proposal = proposals[proposalId];

        require(proposal.id != 0, "Governance: proposal not found");
        require(proposal.state == ProposalState.ACTIVE, "Governance: not active");
        require(!hasVoted[proposalId][msg.sender], "Governance: already voted");
        require(support <= 2, "Governance: invalid vote");

        uint256 weight = chipToken.balanceOf(msg.sender);
        require(weight > 0, "Governance: no voting power");

        hasVoted[proposalId][msg.sender] = true;
        votes[proposalId][msg.sender] = support;

        if (support == uint8(VoteType.FOR)) {
            proposal.forVotes += weight;
        } else if (support == uint8(VoteType.AGAINST)) {
            proposal.againstVotes += weight;
        } else {
            proposal.abstainVotes += weight;
        }

        emit VoteCast(proposalId, msg.sender, support, weight);

        // Update state if voting ended
        _updateProposalState(proposalId);
    }

    /**
     * @dev Execute a successful proposal
     * @param proposalId Proposal ID
     */
    function executeProposal(uint256 proposalId) 
        external 
        whenNotPaused 
        returns (bool) 
    {
        Proposal storage proposal = proposals[proposalId];

        require(proposal.id != 0, "Governance: proposal not found");
        require(proposal.state == ProposalState.SUCCEEDED, "Governance: not succeeded");
        require(!proposal.executed, "Governance: already executed");

        proposal.executed = true;
        proposal.state = ProposalState.EXECUTED;

        activeProposals.remove(proposalId);

        // Execute the proposal
        (bool success, ) = proposal.target.call(proposal.callData);

        emit ProposalExecuted(proposalId, success);
        emit ProposalStateChanged(proposalId, ProposalState.EXECUTED);

        return success;
    }

    /**
     * @dev Update proposal state based on votes
     */
    function updateProposalState(uint256 proposalId) external {
        _updateProposalState(proposalId);
    }

    function _updateProposalState(uint256 proposalId) internal {
        Proposal storage proposal = proposals[proposalId];

        if (proposal.state != ProposalState.ACTIVE) {
            return;
        }

        // Check if voting period ended (approximate with block number)
        if (block.number >= proposal.endBlock) {
            uint256 totalVotes = proposal.forVotes + proposal.againstVotes + proposal.abstainVotes;

            if (totalVotes < proposal.quorumVotes) {
                // Quorum not reached
                proposal.state = ProposalState.DEFEATED;
            } else if (proposal.forVotes > proposal.againstVotes) {
                proposal.state = ProposalState.SUCCEEDED;
            } else {
                proposal.state = ProposalState.DEFEATED;
            }

            activeProposals.remove(proposalId);
            emit ProposalStateChanged(proposalId, proposal.state);
        }
    }

    // ============ View Functions ============

    /**
     * @dev Get proposal state
     */
    function getProposalState(uint256 proposalId) external view returns (ProposalState) {
        Proposal storage proposal = proposals[proposalId];

        if (proposal.id == 0) {
            return ProposalState.PENDING;
        }

        // Check if expired (not executed within 7 days after success)
        if (proposal.state == ProposalState.SUCCEEDED) {
            if (block.number > proposal.endBlock + (7 days / 3 seconds)) {
                return ProposalState.EXPIRED;
            }
        }

        return proposal.state;
    }

    /**
     * @dev Get proposal details
     */
    function getProposal(uint256 proposalId) external view returns (
        uint256 id,
        address proposer,
        address target,
        string memory description,
        uint256 forVotes,
        uint256 againstVotes,
        uint256 abstainVotes,
        ProposalState state,
        bool executed
    ) {
        Proposal storage proposal = proposals[proposalId];
        return (
            proposal.id,
            proposal.proposer,
            proposal.target,
            proposal.description,
            proposal.forVotes,
            proposal.againstVotes,
            proposal.abstainVotes,
            proposal.state,
            proposal.executed
        );
    }

    /**
     * @dev Get active proposals
     */
    function getActiveProposals() external view returns (uint256[] memory) {
        uint256 length = activeProposals.length();
        uint256[] memory result = new uint256[](length);

        for (uint256 i = 0; i < length; i++) {
            result[i] = activeProposals.at(i);
        }

        return result;
    }

    /**
     * @dev Check if address has voted on proposal
     */
    function getVote(uint256 proposalId, address voter) external view returns (bool, uint256) {
        return (hasVoted[proposalId][voter], votes[proposalId][voter]);
    }

    /**
     * @dev Calculate quorum required
     */
    function quorum() external view returns (uint256) {
        return chipToken.totalSupply() * quorumNumerator / 1000;
    }

    // ============ Admin Functions ============

    function setVotingPeriod(uint256 _votingPeriod) external onlyOwner {
        require(_votingPeriod >= 1 days && _votingPeriod <= 14 days, "Governance: invalid period");
        votingPeriod = _votingPeriod;
        emit VotingPeriodUpdated(_votingPeriod);
    }

    function setProposalThreshold(uint256 _threshold) external onlyOwner {
        proposalThreshold = _threshold;
        emit ProposalThresholdUpdated(_threshold);
    }

    function setQuorumNumerator(uint256 _quorumNumerator) external onlyOwner {
        require(_quorumNumerator <= 500, "Governance: quorum too high"); // Max 50%
        quorumNumerator = _quorumNumerator;
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    // ============ Receive ============

    receive() external payable {}
    fallback() external payable {}
}

contracts/Staking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

/**
 * @title Staking
 * @dev CHIP Token Staking Contract
 * Stake CHIP to earn platform revenue share and VIP benefits
 * 
 * Reward Rule: Daily Reward = clamp(max(stakes) * (userStake / totalStaked) / 30, 1 CHIP, 1000 CHIP)
 * 
 * Examples:
 * - If max stake is 30000 CHIP, total staked is 30000 CHIP, user stakes 30000 CHIP:
 *   Daily reward = 30000 * 30000/30000 / 30 = 1000 CHIP (capped at MAX)
 * - If max stake is 30000 CHIP, total staked is 60000 CHIP, user stakes 1000 CHIP:
 *   Daily reward = 30000 * 1000/60000 / 30 = 16.67 CHIP
 * - If max stake is 100 CHIP, total staked is 100 CHIP, user stakes 100 CHIP:
 *   Daily reward = 100 * 100/100 / 30 = 3.33 CHIP
 */
contract Staking is Ownable, Pausable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    // ============ Constants ============

    uint256 public constant MIN_STAKE = 100 * 1e6;          // 100 CHIP minimum
    uint256 public constant MIN_LOCK_DURATION = 30 days;    // 30 days minimum
    uint256 public constant MAX_LOCK_DURATION = 365 days;   // 365 days maximum
    uint256 public constant EARLY_UNSTAKE_PENALTY = 1000;   // 10% penalty (basis points)

    // Reward limits
    uint256 public constant MIN_DAILY_REWARD = 1 * 1e6;     // 1 CHIP minimum daily reward
    uint256 public constant MAX_DAILY_REWARD = 1000 * 1e6;  // 1000 CHIP maximum daily reward
    uint256 public constant REWARD_DENOMINATOR = 30;        // Divide by 30 for daily reward

    // ============ Structs ============

    struct StakeInfo {
        uint256 amount;
        uint256 startTime;
        uint256 lockedUntil;
        uint256 lastClaimTime;    // Last time rewards were claimed
        bool isActive;
    }

    // ============ State Variables ============

    IERC20 public chipToken;

    uint256 public totalStaked;
    uint256 public totalRewardPool;
    uint256 public totalRewardsClaimed;

    uint256 public minLockDuration = MIN_LOCK_DURATION;
    uint256 public maxLockDuration = MAX_LOCK_DURATION;
    uint256 public earlyUnstakePenalty = EARLY_UNSTAKE_PENALTY;

    // Track largest stake for reward calculation
    uint256 public largestStake;

    // Track all stakers for largestStake recalculation
    address[] public stakers;
    mapping(address => uint256) public stakerIndex; // 1-based index, 0 means not in array

    mapping(address => StakeInfo) public stakes;
    mapping(address => uint256) public totalUserRewardsClaimed;

    // ============ Events ============

    event Staked(address indexed user, uint256 amount, uint256 lockDuration);
    event Unstaked(address indexed user, uint256 amount, uint256 penalty);
    event RewardClaimed(address indexed user, uint256 amount);
    event RewardAdded(uint256 amount, uint256 totalPool);
    event PenaltyUpdated(uint256 newPenalty);
    event LargestStakeUpdated(uint256 newLargestStake);

    // ============ Constructor ============

    constructor(address _chipToken)  {
        require(_chipToken != address(0), "Staking: invalid token");
        chipToken = IERC20(_chipToken);
    }

    // ============ Core Functions ============

    /**
     * @dev Stake CHIP tokens
     * @param amount Amount to stake
     * @param lockDuration Lock duration in seconds
     */
    function stake(uint256 amount, uint256 lockDuration) 
        external 
        nonReentrant 
        whenNotPaused 
    {
        require(amount >= MIN_STAKE, "Staking: below minimum stake");
        require(lockDuration >= minLockDuration, "Staking: lock too short");
        require(lockDuration <= maxLockDuration, "Staking: lock too long");

        // Transfer tokens
        chipToken.safeTransferFrom(msg.sender, address(this), amount);

        // Create or update stake
        StakeInfo storage userStake = stakes[msg.sender];

        if (userStake.isActive) {
            // Add to existing stake
            userStake.amount += amount;
            userStake.lockedUntil = block.timestamp + lockDuration;
        } else {
            // New stake
            userStake.amount = amount;
            userStake.startTime = block.timestamp;
            userStake.lockedUntil = block.timestamp + lockDuration;
            userStake.lastClaimTime = block.timestamp;
            userStake.isActive = true;

            // Add to stakers array (only for new stakers)
            _addStaker(msg.sender);
        }

        totalStaked += amount;

        // Update largestStake if needed
        if (userStake.amount > largestStake) {
            largestStake = userStake.amount;
            emit LargestStakeUpdated(largestStake);
        }

        emit Staked(msg.sender, amount, lockDuration);
    }

    /**
     * @dev Unstake CHIP tokens
     * @param amount Amount to unstake
     */
    function unstake(uint256 amount) 
        external 
        nonReentrant 
        whenNotPaused 
    {
        StakeInfo storage userStake = stakes[msg.sender];

        require(userStake.isActive, "Staking: no active stake");
        require(userStake.amount >= amount, "Staking: insufficient stake");

        uint256 penalty = 0;
        uint256 transferAmount = amount;

        // Calculate penalty if unstaking early
        if (block.timestamp < userStake.lockedUntil) {
            penalty = amount * earlyUnstakePenalty / 10000;
            transferAmount = amount - penalty;
        }

        // Update stake
        userStake.amount -= amount;

        if (userStake.amount == 0) {
            userStake.isActive = false;
            // Remove from stakers array
            _removeStaker(msg.sender);
        }

        totalStaked -= amount;

        // Update largestStake if this was the largest staker
        if (userStake.amount < largestStake || largestStake == 0) {
            _updateLargestStake();
        }

        // Transfer tokens to user
        chipToken.safeTransfer(msg.sender, transferAmount);

        // Send penalty to owner
        if (penalty > 0) {
            chipToken.safeTransfer(owner(), penalty);
        }

        emit Unstaked(msg.sender, amount, penalty);
    }

    /**
     * @dev Claim pending rewards
     * Daily Reward = clamp(largestStake * (userStake / totalStaked) / 30, MIN, MAX)
     */
    function claimReward() external nonReentrant whenNotPaused {
        StakeInfo storage userStake = stakes[msg.sender];

        require(userStake.isActive, "Staking: no active stake");
        require(userStake.amount > 0, "Staking: no stake amount");
        require(totalStaked > 0, "Staking: no total staked");

        // Calculate reward
        uint256 stakeDuration = block.timestamp - userStake.lastClaimTime;

        // Daily reward = largestStake * (userStake / totalStaked) / 30
        // Formula: reward = largestStake * userStake.amount * stakeDuration / (totalStaked * 30 * 1 day)
        uint256 reward = largestStake * userStake.amount * stakeDuration / (totalStaked * REWARD_DENOMINATOR * 1 days);

        // Apply daily limits
        uint256 dailyMin = MIN_DAILY_REWARD * stakeDuration / 1 days;
        uint256 dailyMax = MAX_DAILY_REWARD * stakeDuration / 1 days;

        if (reward < dailyMin) {
            reward = dailyMin;
        } else if (reward > dailyMax) {
            reward = dailyMax;
        }

        require(reward > 0, "Staking: no rewards to claim");

        // Check reward pool balance
        uint256 availableRewards = chipToken.balanceOf(address(this)) - totalStaked;
        require(reward <= availableRewards, "Staking: insufficient reward pool");

        // Update last claim time
        userStake.lastClaimTime = block.timestamp;

        // Update total claimed
        totalRewardsClaimed += reward;
        totalUserRewardsClaimed[msg.sender] += reward;

        // Transfer reward
        chipToken.safeTransfer(msg.sender, reward);

        emit RewardClaimed(msg.sender, reward);
    }

    /**
     * @dev Add rewards to the pool (called by platform)
     * @param amount Amount of CHIP to add
     */
    function addReward(uint256 amount) external nonReentrant {
        chipToken.safeTransferFrom(msg.sender, address(this), amount);
        totalRewardPool += amount;
        emit RewardAdded(amount, totalRewardPool);
    }

    // ============ Internal Functions ============

    /**
     * @dev Add staker to the array
     */
    function _addStaker(address staker) internal {
        if (stakerIndex[staker] == 0) {
            stakers.push(staker);
            stakerIndex[staker] = stakers.length; // 1-based index
        }
    }

    /**
     * @dev Remove staker from the array
     */
    function _removeStaker(address staker) internal {
        uint256 index = stakerIndex[staker];
        if (index == 0) return; // Not in array

        // Move last element to the position of the element to delete
        uint256 lastIndex = stakers.length;
        if (index != lastIndex) {
            address lastStaker = stakers[lastIndex - 1];
            stakers[index - 1] = lastStaker;
            stakerIndex[lastStaker] = index;
        }

        // Remove last element
        stakers.pop();
        stakerIndex[staker] = 0;
    }

    /**
     * @dev Recalculate largestStake from all active stakers
     */
    function _updateLargestStake() internal {
        uint256 maxStake = 0;

        for (uint256 i = 0; i < stakers.length; i++) {
            address staker = stakers[i];
            StakeInfo storage s = stakes[staker];

            if (s.isActive && s.amount > maxStake) {
                maxStake = s.amount;
            }
        }

        largestStake = maxStake;
        emit LargestStakeUpdated(largestStake);
    }

    // ============ View Functions ============

    /**
     * @dev Get pending reward for user
     * Daily Reward = clamp(largestStake * (userStake / totalStaked) / 30, MIN, MAX)
     */
    function getPendingReward(address user) external view returns (uint256) {
        StakeInfo storage userStake = stakes[user];

        if (!userStake.isActive || userStake.amount == 0 || totalStaked == 0) {
            return 0;
        }

        uint256 stakeDuration = block.timestamp - userStake.lastClaimTime;

        // Daily reward calculation
        uint256 reward = largestStake * userStake.amount * stakeDuration / (totalStaked * REWARD_DENOMINATOR * 1 days);

        // Apply limits
        uint256 dailyMin = MIN_DAILY_REWARD * stakeDuration / 1 days;
        uint256 dailyMax = MAX_DAILY_REWARD * stakeDuration / 1 days;

        if (reward < dailyMin) {
            return dailyMin;
        } else if (reward > dailyMax) {
            return dailyMax;
        }

        return reward;
    }

    /**
     * @dev Get stake info for user
     */
    function getStakeInfo(address user) external view returns (
        uint256 amount,
        uint256 startTime,
        uint256 lockedUntil,
        bool isLocked,
        bool isActive
    ) {
        StakeInfo storage userStake = stakes[user];
        return (
            userStake.amount,
            userStake.startTime,
            userStake.lockedUntil,
            block.timestamp < userStake.lockedUntil,
            userStake.isActive
        );
    }

    /**
     * @dev Check if user's stake is locked
     */
    function isLocked(address user) external view returns (bool) {
        return block.timestamp < stakes[user].lockedUntil;
    }

    /**
     * @dev Get remaining lock time for user
     */
    function getRemainingLockTime(address user) external view returns (uint256) {
        uint256 lockedUntil = stakes[user].lockedUntil;

        if (block.timestamp >= lockedUntil) {
            return 0;
        }

        return lockedUntil - block.timestamp;
    }

    /**
     * @dev Get total number of stakers
     */
    function getStakersCount() external view returns (uint256) {
        return stakers.length;
    }

    /**
     * @dev Get staker address by index
     */
    function getStaker(uint256 index) external view returns (address) {
        require(index < stakers.length, "Staking: index out of bounds");
        return stakers[index];
    }

    // ============ Admin Functions ============

    function setLockDuration(uint256 _minDuration, uint256 _maxDuration) external onlyOwner {
        require(_minDuration < _maxDuration, "Staking: invalid durations");
        minLockDuration = _minDuration;
        maxLockDuration = _maxDuration;
    }

    function setEarlyUnstakePenalty(uint256 _penalty) external onlyOwner {
        require(_penalty <= 3000, "Staking: penalty too high"); // Max 30%
        earlyUnstakePenalty = _penalty;
        emit PenaltyUpdated(_penalty);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    // ============ Emergency Functions ============

    function emergencyUnstake() external nonReentrant {
        StakeInfo storage userStake = stakes[msg.sender];

        require(userStake.isActive, "Staking: no active stake");

        uint256 amount = userStake.amount;
        uint256 penalty = amount * earlyUnstakePenalty / 10000;
        uint256 transferAmount = amount - penalty;

        userStake.amount = 0;
        userStake.isActive = false;
        totalStaked -= amount;

        // Remove from stakers array
        _removeStaker(msg.sender);

        // Update largestStake
        _updateLargestStake();

        chipToken.safeTransfer(msg.sender, transferAmount);
        chipToken.safeTransfer(owner(), penalty);

        emit Unstaked(msg.sender, amount, penalty);
    }

    // ============ Receive ============

    receive() external payable {}
    fallback() external payable {}
}

contracts/Tournament.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title Tournament
 * @dev Sit & Go Tournament Contract for Texas Hold'em Poker
 * Supports 2/3/6 player SNG and 9 player scheduled tournaments
 */
contract Tournament is ReentrancyGuard, Ownable, Pausable {

    // ============ Enums ============

    enum TournamentType { SNG, SCHEDULED }
    enum StartMode { INSTANT, SCHEDULED }
    enum TournamentStatus { WAITING, IN_PROGRESS, COMPLETED, CANCELLED }

    // ============ Structs ============

    struct TournamentConfig {
        TournamentType tournamentType;
        uint8 playerCount;           // 2, 3, 6, or 9
        uint256 buyIn;               // Buy-in amount in SUN
        uint256 rakeRate;            // Rake rate in basis points (500 = 5%)
        uint256[] prizeDistribution; // Percentages for each position (sum = 100)
        uint256 initialChips;        // Starting chips for each player
        StartMode startMode;
        uint256 waitTimeout;         // Wait timeout in seconds for scheduled
    }

    struct TournamentInfo {
        uint256 configId;
        TournamentStatus status;
        address[] players;
        uint256 prizePool;
        uint256 rakeCollected;
        uint256 startTime;
        uint256 endTime;
        address[] finalRankings;
        mapping(address => uint256) prizes;
        mapping(address => bool) hasClaimed;
    }

    // ============ State Variables ============

    address public serverWallet;
    address public chipToken;          // CHIP token address for rewards

    uint256 public tournamentCounter;
    mapping(uint256 => TournamentConfig) public configs;
    mapping(uint256 => TournamentInfo) public tournaments;
    mapping(address => uint256) public playerCurrentTournament;

    uint256[] public activeTournaments;

    // ============ Events ============

    event TournamentConfigCreated(uint256 indexed configId, TournamentType tournamentType, uint8 playerCount);
    event TournamentCreated(uint256 indexed tournamentId, uint256 indexed configId);
    event PlayerJoined(uint256 indexed tournamentId, address indexed player, uint8 position);
    event PlayerLeft(uint256 indexed tournamentId, address indexed player);
    event TournamentStarted(uint256 indexed tournamentId, uint256 prizePool, uint256 playerCount);
    event TournamentFinished(uint256 indexed tournamentId, address[] rankings, uint256 rakeCollected);
    event PrizeClaimed(uint256 indexed tournamentId, address indexed player, uint256 amount);
    event TournamentCancelled(uint256 indexed tournamentId);

    // ============ Modifiers ============

    modifier onlyServer() {
        require(msg.sender == serverWallet, "Tournament: caller is not server");
        _;
    }

    modifier notInTournament() {
        require(playerCurrentTournament[msg.sender] == 0, "Tournament: already in tournament");
        _;
    }

    modifier tournamentExists(uint256 tournamentId) {
        require(tournamentId > 0 && tournamentId <= tournamentCounter, "Tournament: does not exist");
        _;
    }

    modifier tournamentWaiting(uint256 tournamentId) {
        require(tournaments[tournamentId].status == TournamentStatus.WAITING, "Tournament: not waiting");
        _;
    }

    // ============ Constructor ============

    constructor(address _serverWallet, address _chipToken)  {
        require(_serverWallet != address(0), "Tournament: invalid server wallet");
        serverWallet = _serverWallet;
        chipToken = _chipToken;
        tournamentCounter = 0;

        // Initialize default tournament configurations
        _initializeDefaultConfigs();
    }

    /**
     * @dev Initialize default tournament configurations
     */
    function _initializeDefaultConfigs() internal {
        // Config 1: 2-player SNG, 100 TRX buy-in, 5% rake, 70/30 split
        uint256[] memory prize2 = new uint256[](2);
        prize2[0] = 70;
        prize2[1] = 30;
        configs[1] = TournamentConfig({
            tournamentType: TournamentType.SNG,
            playerCount: 2,
            buyIn: 100 * 1e6,         // 100 TRX
            rakeRate: 500,            // 5%
            prizeDistribution: prize2,
            initialChips: 1000,       // 1000 starting chips
            startMode: StartMode.INSTANT,
            waitTimeout: 0
        });

        // Config 2: 3-player SNG, 50 TRX buy-in, 5% rake, 50/30/20 split
        uint256[] memory prize3 = new uint256[](3);
        prize3[0] = 50;
        prize3[1] = 30;
        prize3[2] = 20;
        configs[2] = TournamentConfig({
            tournamentType: TournamentType.SNG,
            playerCount: 3,
            buyIn: 50 * 1e6,          // 50 TRX
            rakeRate: 500,            // 5%
            prizeDistribution: prize3,
            initialChips: 1500,
            startMode: StartMode.INSTANT,
            waitTimeout: 0
        });

        // Config 3: 6-player SNG, 50 TRX buy-in, 5% rake, 50/30/20 split
        uint256[] memory prize6 = new uint256[](3);
        prize6[0] = 50;
        prize6[1] = 30;
        prize6[2] = 20;
        configs[3] = TournamentConfig({
            tournamentType: TournamentType.SNG,
            playerCount: 6,
            buyIn: 50 * 1e6,          // 50 TRX
            rakeRate: 500,            // 5%
            prizeDistribution: prize6,
            initialChips: 1500,
            startMode: StartMode.INSTANT,
            waitTimeout: 0
        });

        // Config 4: 9-player Scheduled, 100 TRX buy-in, 5% rake, 45/25/15/10/5 split
        uint256[] memory prize9 = new uint256[](5);
        prize9[0] = 45;
        prize9[1] = 25;
        prize9[2] = 15;
        prize9[3] = 10;
        prize9[4] = 5;
        configs[4] = TournamentConfig({
            tournamentType: TournamentType.SCHEDULED,
            playerCount: 9,
            buyIn: 100 * 1e6,         // 100 TRX
            rakeRate: 500,            // 5%
            prizeDistribution: prize9,
            initialChips: 2000,
            startMode: StartMode.SCHEDULED,
            waitTimeout: 5 minutes
        });

        tournamentCounter = 4;
    }

    // ============ Configuration Functions ============

    /**
     * @dev Create a new tournament configuration
     * @param _tournamentType SNG or SCHEDULED
     * @param _playerCount Number of players (2, 3, 6, or 9)
     * @param _buyIn Buy-in amount in SUN
     * @param _rakeRate Rake rate in basis points
     * @param _prizeDistribution Array of percentages for prize distribution
     * @param _initialChips Starting chips for each player
     * @param _startMode INSTANT or SCHEDULED
     * @param _waitTimeout Wait timeout in seconds
     */
    function createTournamentConfig(
        TournamentType _tournamentType,
        uint8 _playerCount,
        uint256 _buyIn,
        uint256 _rakeRate,
        uint256[] calldata _prizeDistribution,
        uint256 _initialChips,
        StartMode _startMode,
        uint256 _waitTimeout
    ) external onlyOwner returns (uint256) {
        require(_playerCount == 2 || _playerCount == 3 || _playerCount == 6 || _playerCount == 9, 
            "Tournament: invalid player count");
        require(_buyIn > 0, "Tournament: buy-in must be greater than 0");
        require(_rakeRate <= 1000, "Tournament: rake rate too high"); // Max 10%
        require(_prizeDistribution.length > 0, "Tournament: empty prize distribution");

        // Validate prize distribution sums to 100
        uint256 total = 0;
        for (uint256 i = 0; i < _prizeDistribution.length; i++) {
            total += _prizeDistribution[i];
        }
        require(total == 100, "Tournament: prize distribution must sum to 100");

        tournamentCounter++;
        uint256 configId = tournamentCounter;

        configs[configId] = TournamentConfig({
            tournamentType: _tournamentType,
            playerCount: _playerCount,
            buyIn: _buyIn,
            rakeRate: _rakeRate,
            prizeDistribution: _prizeDistribution,
            initialChips: _initialChips,
            startMode: _startMode,
            waitTimeout: _waitTimeout
        });

        emit TournamentConfigCreated(configId, _tournamentType, _playerCount);

        return configId;
    }

    // ============ Tournament Functions ============

    /**
     * @dev Create a new tournament from a configuration
     * @param configId The configuration ID to use
     */
    function createTournament(uint256 configId) external onlyServer returns (uint256) {
        require(configs[configId].playerCount > 0, "Tournament: config does not exist");

        tournamentCounter++;
        uint256 newTournamentId = tournamentCounter;

        TournamentInfo storage tournament = tournaments[newTournamentId];
        tournament.configId = configId;
        tournament.status = TournamentStatus.WAITING;
        tournament.prizePool = 0;
        tournament.rakeCollected = 0;
        tournament.startTime = 0;
        tournament.endTime = 0;

        activeTournaments.push(newTournamentId);

        emit TournamentCreated(newTournamentId, configId);

        return newTournamentId;
    }

    /**
     * @dev Join a tournament by paying the buy-in
     * @param tournamentId The tournament ID to join
     */
    function joinTournament(uint256 tournamentId) 
        external 
        payable 
        nonReentrant 
        whenNotPaused
        tournamentExists(tournamentId)
        tournamentWaiting(tournamentId)
        notInTournament
    {
        TournamentInfo storage tournament = tournaments[tournamentId];
        TournamentConfig storage config = configs[tournament.configId];

        require(msg.value == config.buyIn, "Tournament: incorrect buy-in amount");
        require(tournament.players.length < config.playerCount, "Tournament: already full");
        require(!hasPlayerJoined(tournamentId, msg.sender), "Tournament: already joined");

        tournament.players.push(msg.sender);
        tournament.prizePool += msg.value;
        playerCurrentTournament[msg.sender] = tournamentId;

        emit PlayerJoined(tournamentId, msg.sender, uint8(tournament.players.length));
    }

    /**
     * @dev Cancel join and get refund
     * @param tournamentId The tournament ID
     */
    function cancelJoin(uint256 tournamentId) 
        external 
        nonReentrant 
        tournamentExists(tournamentId)
        tournamentWaiting(tournamentId)
    {
        TournamentInfo storage tournament = tournaments[tournamentId];
        TournamentConfig storage config = configs[tournament.configId];

        require(hasPlayerJoined(tournamentId, msg.sender), "Tournament: not joined");

        // Find and remove player
        uint256 playerIndex = findPlayerIndex(tournamentId, msg.sender);
        require(playerIndex < tournament.players.length, "Tournament: player not found");

        // Remove player by swapping with last and popping
        tournament.players[playerIndex] = tournament.players[tournament.players.length - 1];
        tournament.players.pop();

        tournament.prizePool -= config.buyIn;
        playerCurrentTournament[msg.sender] = 0;

        // Refund
        (bool success, ) = payable(msg.sender).call{value: config.buyIn}("");
        require(success, "Tournament: refund failed");

        emit PlayerLeft(tournamentId, msg.sender);
    }

    /**
     * @dev Start the tournament (only server)
     * @param tournamentId The tournament ID
     */
    function startTournament(uint256 tournamentId) 
        external 
        onlyServer 
        tournamentExists(tournamentId)
        tournamentWaiting(tournamentId)
    {
        TournamentInfo storage tournament = tournaments[tournamentId];
        TournamentConfig storage config = configs[tournament.configId];

        require(tournament.players.length == config.playerCount, "Tournament: not full");

        // Calculate rake
        uint256 totalPool = tournament.prizePool;
        tournament.rakeCollected = (totalPool * config.rakeRate) / 10000;
        tournament.prizePool = totalPool - tournament.rakeCollected;
        tournament.status = TournamentStatus.IN_PROGRESS;
        tournament.startTime = block.timestamp;

        emit TournamentStarted(tournamentId, tournament.prizePool, tournament.players.length);
    }

    /**
     * @dev Cancel tournament and refund all players
     * @param tournamentId The tournament ID
     */
    function cancelTournament(uint256 tournamentId) 
        external 
        onlyServer 
        tournamentExists(tournamentId)
    {
        TournamentInfo storage tournament = tournaments[tournamentId];
        require(tournament.status == TournamentStatus.WAITING, "Tournament: cannot cancel");

        tournament.status = TournamentStatus.CANCELLED;

        // Refund all players
        TournamentConfig storage config = configs[tournament.configId];
        uint256 buyIn = config.buyIn;

        for (uint256 i = 0; i < tournament.players.length; i++) {
            address player = tournament.players[i];
            playerCurrentTournament[player] = 0;

            (bool success, ) = payable(player).call{value: buyIn}("");
            require(success, "Tournament: refund failed");
        }

        tournament.prizePool = 0;

        emit TournamentCancelled(tournamentId);
    }

    /**
     * @dev Finish tournament and set final rankings
     * @param tournamentId The tournament ID
     * @param rankings Array of player addresses in order of finish (winner first)
     */
    function finishTournament(uint256 tournamentId, address[] calldata rankings) 
        external 
        onlyServer 
        tournamentExists(tournamentId)
    {
        TournamentInfo storage tournament = tournaments[tournamentId];
        TournamentConfig storage config = configs[tournament.configId];

        require(tournament.status == TournamentStatus.IN_PROGRESS, "Tournament: not in progress");
        require(rankings.length == tournament.players.length, "Tournament: invalid rankings");

        tournament.status = TournamentStatus.COMPLETED;
        tournament.endTime = block.timestamp;
        tournament.finalRankings = rankings;

        // Calculate prizes based on distribution
        for (uint256 i = 0; i < rankings.length && i < config.prizeDistribution.length; i++) {
            uint256 prize = (tournament.prizePool * config.prizeDistribution[i]) / 100;
            tournament.prizes[rankings[i]] = prize;
        }

        // Clear player current tournament
        for (uint256 i = 0; i < tournament.players.length; i++) {
            playerCurrentTournament[tournament.players[i]] = 0;
        }

        // Transfer rake to server wallet
        if (tournament.rakeCollected > 0) {
            (bool success, ) = payable(serverWallet).call{value: tournament.rakeCollected}("");
            require(success, "Tournament: rake transfer failed");
        }

        emit TournamentFinished(tournamentId, rankings, tournament.rakeCollected);
    }

    /**
     * @dev Claim prize for finished tournament
     * @param tournamentId The tournament ID
     */
    function claimPrize(uint256 tournamentId) 
        external 
        nonReentrant 
        tournamentExists(tournamentId)
    {
        TournamentInfo storage tournament = tournaments[tournamentId];

        require(tournament.status == TournamentStatus.COMPLETED, "Tournament: not completed");
        require(!tournament.hasClaimed[msg.sender], "Tournament: already claimed");
        require(tournament.prizes[msg.sender] > 0, "Tournament: no prize");

        uint256 prize = tournament.prizes[msg.sender];
        tournament.hasClaimed[msg.sender] = true;

        (bool success, ) = payable(msg.sender).call{value: prize}("");
        require(success, "Tournament: prize transfer failed");

        emit PrizeClaimed(tournamentId, msg.sender, prize);
    }

    // ============ View Functions ============

    function getTournamentConfig(uint256 configId) external view returns (
        TournamentType tournamentType,
        uint8 playerCount,
        uint256 buyIn,
        uint256 rakeRate,
        uint256[] memory prizeDistribution,
        uint256 initialChips,
        StartMode startMode,
        uint256 waitTimeout
    ) {
        TournamentConfig storage config = configs[configId];
        return (
            config.tournamentType,
            config.playerCount,
            config.buyIn,
            config.rakeRate,
            config.prizeDistribution,
            config.initialChips,
            config.startMode,
            config.waitTimeout
        );
    }

    function getTournamentInfo(uint256 tournamentId) external view returns (
        uint256 configId,
        TournamentStatus status,
        address[] memory players,
        uint256 prizePool,
        uint256 rakeCollected,
        uint256 startTime,
        uint256 endTime,
        address[] memory finalRankings
    ) {
        TournamentInfo storage tournament = tournaments[tournamentId];
        return (
            tournament.configId,
            tournament.status,
            tournament.players,
            tournament.prizePool,
            tournament.rakeCollected,
            tournament.startTime,
            tournament.endTime,
            tournament.finalRankings
        );
    }

    function getPlayerPrize(uint256 tournamentId, address player) external view returns (uint256) {
        return tournaments[tournamentId].prizes[player];
    }

    function hasPlayerJoined(uint256 tournamentId, address player) public view returns (bool) {
        TournamentInfo storage tournament = tournaments[tournamentId];
        for (uint256 i = 0; i < tournament.players.length; i++) {
            if (tournament.players[i] == player) {
                return true;
            }
        }
        return false;
    }

    function findPlayerIndex(uint256 tournamentId, address player) public view returns (uint256) {
        TournamentInfo storage tournament = tournaments[tournamentId];
        for (uint256 i = 0; i < tournament.players.length; i++) {
            if (tournament.players[i] == player) {
                return i;
            }
        }
        return tournament.players.length; // Not found
    }

    function getActiveTournaments() external view returns (uint256[] memory) {
        return activeTournaments;
    }

    function getTournamentPlayers(uint256 tournamentId) external view returns (address[] memory) {
        return tournaments[tournamentId].players;
    }

    // ============ Admin Functions ============

    function setServerWallet(address _serverWallet) external onlyOwner {
        require(_serverWallet != address(0), "Tournament: invalid address");
        serverWallet = _serverWallet;
    }

    function setChipToken(address _chipToken) external onlyOwner {
        chipToken = _chipToken;
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    // ============ Emergency Functions ============

    function emergencyWithdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        (bool success, ) = payable(owner()).call{value: balance}("");
        require(success, "Tournament: withdrawal failed");
    }

    // ============ Receive ============

    receive() external payable {}
    fallback() external payable {}
}

